#include <bits/stdc++.h>
using namespace std;
struct Node{
    string name;
    char t;
    long long v;
}a[200005];
bool cmp(Node x,Node y){
    if(x.t==y.t)
        return x.v>y.v;
    return x.t>y.t;
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n+m;i++)
        cin>>a[i].name>>a[i].t>>a[i].v;
    sort(a+1,a+n+m+1,cmp);
    cout<<a[n+3].name<<endl<<a[6].name<<endl<<a[7].name<<endl<<a[8].name<<endl<<a[9].name;
    return 0;
}
